// bundle 用 exported TLA promise 初始化 API；必须等待后再读取 diagram
import * as Penrose from 'https://cdn.jsdelivr.net/npm/@penrose/core@3.3.0/bundle/+esm';
await Penrose.__tla;
const el = document.getElementById('penrose'); el.style.width = '100%';
await Penrose.diagram(
  { domain: data.domain, substance: data.substance, style: data.style, variation: data.variation ?? 'v1', excludeWarnings: [] },
  el,
  async () => undefined
);

